    25→  carouselCards: ProductCard[];
    26→  priceInfo: PriceStripItem[];
    27→  outfitName: string;
    28→}
    29→
    30→/**
    31→ * Process a tool_result Socket.io event into display-ready data.
    32→ *
    33→ * Handles two tool result types:
    34→ * - `display_product`: tries flat lay overlay first, falls back to ProductCarousel cards
    35→ * - `clothing_results`: always maps to ProductCarousel cards (from present_items)
    36→ *
    37→ * Returns null for unknown types or empty items.
    38→ */
    39→export function processToolResult(data: ToolResultData): ProcessedToolResult | null {
    40→  if (!data.items || data.items.length === 0) {
    41→    console.warn("[MirrorV2:ToolResult] No items in:", data.type);
    42→    return null;
    43→  }
    44→
    45→  if (data.type === "display_product") {
    46→    const canvasItems = mapToClothingItems(data.items);
    47→    const priceInfo: PriceStripItem[] = data.items.map((it) => ({
    48→      title: it.title,
    49→      price: it.price,
    50→    }));
    51→    const outfitName = data.outfit_name || "";
    52→
    53→    // Always populate carousel cards for immediate visual feedback
    54→    const carouselCards = mapItemsToCards(data.items);
    55→
    56→    return { canvasItems, carouselCards, priceInfo, outfitName };
    57→  }
    58→
    59→  if (data.type === "clothing_results") {
    60→    const carouselCards = mapItemsToCards(data.items);
    61→    if (carouselCards.length === 0) return null;
    62→    return { canvasItems: [], carouselCards, priceInfo: [], outfitName: "" };
    63→  }
    64→
    65→  console.warn("[MirrorV2:ToolResult] Unknown tool type:", data.type);
    66→  return null;
    67→}
    68→
    69→/** Map raw tool result items to ProductCard format for the carousel. */
    70→function mapItemsToCards(
    71→  items: NonNullable<ToolResultData["items"]>,
    72→): ProductCard[] {
    73→  return items
    74→    .filter((it) => it.image_url)
    75→    .map((it) => ({
    76→      product_id: it.product_id || crypto.randomUUID(),
    77→      title: it.title,
    78→      price: it.price || "",
    79→      image_url: it.image_url!,
    80→      link: it.link || "",
    81→      source: it.source || "",
    82→    }));
    83→}
