    13→  pose: PoseResult | null;
    14→  items: ClothingItem[];
    15→  width: number;
    16→  height: number;
    17→  opacity?: number;
    18→  onImageError?: (itemId: string, error: string) => void;
    19→  onFitStatus?: (statuses: Map<string, FitMethod>) => void;
    20→}
    21→
    22→const CATEGORY_Z_ORDER = {
    23→  bottoms: 0,
    24→  tops: 1,
    25→};
    26→
    27→interface ImageBounds {
    28→  x: number;
    29→  y: number;
    30→  width: number;
    31→  height: number;
    32→}
    33→
    34→/**
    35→ * Detect the bounding box of non-transparent pixels in an image
    36→ * This crops out empty transparent space
    37→ */
    38→function detectImageBounds(img: HTMLImageElement): ImageBounds {
    39→  const canvas = document.createElement('canvas');
    40→  canvas.width = img.width;
    41→  canvas.height = img.height;
    42→  const ctx = canvas.getContext('2d');
    43→  if (!ctx) return { x: 0, y: 0, width: img.width, height: img.height };
    44→
    45→  ctx.drawImage(img, 0, 0);
    46→  const imageData = ctx.getImageData(0, 0, img.width, img.height);
    47→  const pixels = imageData.data;
    48→
    49→  let minX = img.width;
    50→  let minY = img.height;
    51→  let maxX = 0;
    52→  let maxY = 0;
    53→
    54→  // Scan for non-transparent pixels
    55→  for (let y = 0; y < img.height; y++) {
    56→    for (let x = 0; x < img.width; x++) {
    57→      const alpha = pixels[(y * img.width + x) * 4 + 3];
    58→      if (alpha > 10) { // Threshold for "visible"
    59→        if (x < minX) minX = x;
    60→        if (x > maxX) maxX = x;
    61→        if (y < minY) minY = y;
    62→        if (y > maxY) maxY = y;
    63→      }
    64→    }
    65→  }
    66→
    67→  // Add small padding
    68→  const padding = 5;
    69→  minX = Math.max(0, minX - padding);
    70→  minY = Math.max(0, minY - padding);
    71→  maxX = Math.min(img.width, maxX + padding);
    72→  maxY = Math.min(img.height, maxY + padding);
    73→
    74→  return {
    75→    x: minX,
    76→    y: minY,
    77→    width: maxX - minX,
    78→    height: maxY - minY,
    79→  };
    80→}
