    82→export function ClothingCanvas({
    83→  pose,
    84→  items,
    85→  width,
    86→  height,
    87→  opacity = 1.0,
    88→  onImageError,
    89→  onFitStatus,
    90→}: ClothingCanvasProps) {
    91→  const canvasRef = useRef<HTMLCanvasElement>(null);
    92→  const imagesRef = useRef<Map<string, HTMLImageElement>>(new Map());
    93→  const boundsRef = useRef<Map<string, ImageBounds>>(new Map());
    94→  const shoulderAnchorsRef = useRef<Map<string, ShoulderAnchors>>(new Map());
