   104→    waistbandAnchorsRef.current.clear();
   105→    fitStatusRef.current = new Map();
   106→
   107→    const newImages = new Map<string, HTMLImageElement>();
   108→    const loaded = new Set<string>();
   109→    let mounted = true;
   110→
   111→    const loadPromises = items.map((item) => {
   112→      return new Promise<void>((resolve) => {
   113→        // Reuse already loaded images
   114→        if (imagesRef.current.has(item.id)) {
   115→          const existingImg = imagesRef.current.get(item.id)!;
   116→          newImages.set(item.id, existingImg);
