   151→              } else {
   152→                fitStatusRef.current.set(item.id, 'fallback');
   153→              }
   154→            } catch (err) {
   155→              console.warn("[MirrorV2:Canvas] Anchor detection failed, using fallback:", err);
   156→              fitStatusRef.current.set(item.id, 'fallback');
   157→            }
   158→          } else if (item.category === 'bottoms') {
   159→            try {
   160→              const waistbandAnchors = detectWaistband(img);
   161→              if (waistbandAnchors) {
   162→                waistbandAnchorsRef.current.set(item.id, waistbandAnchors);
   163→                fitStatusRef.current.set(item.id, 'precise');
