   218→    }
   219→
   220→    // Update last known pose
   221→    if (pose) {
   222→      lastPoseRef.current = pose;
   223→    }
   224→
   225→    ctx.clearRect(0, 0, width, height);
   226→
   227→    // Sort items by z-order (bottoms first, then tops)
   228→    const sortedItems = [...items].sort((a, b) => {
   229→      return CATEGORY_Z_ORDER[a.category] - CATEGORY_Z_ORDER[b.category];
   230→    });
   231→
   232→    for (const item of sortedItems) {
   233→      const img = imagesRef.current.get(item.id);
   234→      if (!img || !loadedImages.has(item.id)) continue;
   235→
   236→      const shoulderAnchors = shoulderAnchorsRef.current.get(item.id);
   237→      const waistbandAnchors = waistbandAnchorsRef.current.get(item.id);
   238→
   239→      const quad = getClothingQuad(
   240→        poseToRender.landmarks,
   241→        item.category,
   242→        width,
   243→        height
   244→      );
   245→
   246→      if (!quad) continue;
   247→
   248→      const isFallback = fitStatusRef.current.get(item.id) === 'fallback';
   249→
   250→      // Shoulder seam anchored rendering for tops
   251→      if (item.category === 'tops' && shoulderAnchors) {
   252→        const shirtLeftShoulder = {
   253→          x: shoulderAnchors.leftShoulder.x * img.width,
   254→          y: shoulderAnchors.leftShoulder.y * img.height,
   255→        };
   256→        const shirtRightShoulder = {
   257→          x: shoulderAnchors.rightShoulder.x * img.width,
   258→          y: shoulderAnchors.rightShoulder.y * img.height,
   259→        };
   260→        const shirtLeftHem = {
   261→          x: shoulderAnchors.leftHem.x * img.width,
   262→          y: shoulderAnchors.leftHem.y * img.height,
   263→        };
   264→        const shirtRightHem = {
   265→          x: shoulderAnchors.rightHem.x * img.width,
   266→          y: shoulderAnchors.rightHem.y * img.height,
   267→        };
   268→
   269→        const bodyLeftShoulder = quad.topLeft;
   270→        const bodyRightShoulder = quad.topRight;
   271→        const bodyLeftHip = quad.bottomLeft;
   272→        const bodyRightHip = quad.bottomRight;
   273→
   274→        const shirtShoulderWidth = Math.hypot(
   275→          shirtRightShoulder.x - shirtLeftShoulder.x,
   276→          shirtRightShoulder.y - shirtLeftShoulder.y
   277→        );
   278→        const shirtTorsoHeight = Math.hypot(
   279→          shirtLeftHem.x - shirtLeftShoulder.x,
   280→          shirtLeftHem.y - shirtLeftShoulder.y
   281→        );
   282→
   283→        const bodyShoulderWidth = Math.hypot(
   284→          bodyRightShoulder.x - bodyLeftShoulder.x,
   285→          bodyRightShoulder.y - bodyLeftShoulder.y
   286→        );
   287→        const bodyTorsoHeight = Math.hypot(
   288→          bodyLeftHip.x - bodyLeftShoulder.x,
   289→          bodyLeftHip.y - bodyLeftShoulder.y
   290→        );
   291→
   292→        const scaleX = bodyShoulderWidth / shirtShoulderWidth;
   293→        const scaleY = bodyTorsoHeight / shirtTorsoHeight;
   294→        const scale = (scaleX + scaleY) / 2;
   295→
   296→        const shirtAnchorCenterX = (shirtLeftShoulder.x + shirtRightShoulder.x + shirtLeftHem.x + shirtRightHem.x) / 4;
   297→        const shirtAnchorCenterY = (shirtLeftShoulder.y + shirtRightShoulder.y + shirtLeftHem.y + shirtRightHem.y) / 4;
   298→
   299→        const bodyCenterX = (bodyLeftShoulder.x + bodyRightShoulder.x + bodyLeftHip.x + bodyRightHip.x) / 4;
   300→        const bodyCenterY = (bodyLeftShoulder.y + bodyRightShoulder.y + bodyLeftHip.y + bodyRightHip.y) / 4;
   301→
   302→        const imgCenterX = img.width / 2;
   303→        const imgCenterY = img.height / 2;
   304→
   305→        const offsetX = (shirtAnchorCenterX - imgCenterX) * scale;
   306→        const offsetY = (shirtAnchorCenterY - imgCenterY) * scale;
   307→
   308→        const finalCenterX = bodyCenterX - offsetX;
   309→        const finalCenterY = bodyCenterY - offsetY;
   310→
   311→        const rotation = Math.atan2(
   312→          bodyRightShoulder.y - bodyLeftShoulder.y,
   313→          bodyRightShoulder.x - bodyLeftShoulder.x
   314→        ) + Math.PI;
   315→
   316→        const renderWidth = img.width * scale;
   317→        const renderHeight = img.height * scale;
   318→
   319→        ctx.save();
   320→        ctx.translate(finalCenterX, finalCenterY);
   321→        ctx.rotate(rotation);
   322→        ctx.scale(-1, 1);
   323→        ctx.globalAlpha = opacity;
   324→
   325→        ctx.drawImage(
   326→          img,
   327→          0, 0, img.width, img.height,
   328→          -renderWidth / 2, -renderHeight / 2, renderWidth, renderHeight
   329→        );
   330→
   331→        ctx.restore();
   332→      } else if (item.category === 'bottoms' && waistbandAnchors && waistbandAnchors.topLeft) {
   333→        // Waistband anchored rendering for bottoms
   334→        const imgTopLeft = {
   335→          x: waistbandAnchors.topLeft.x * img.width,
   336→          y: waistbandAnchors.topLeft.y * img.height,
   337→        };
   338→        const imgTopRight = {
   339→          x: waistbandAnchors.topRight.x * img.width,
   340→          y: waistbandAnchors.topRight.y * img.height,
   341→        };
   342→        const imgBottomLeft = {
   343→          x: waistbandAnchors.bottomLeft.x * img.width,
   344→          y: waistbandAnchors.bottomLeft.y * img.height,
   345→        };
   346→        const imgBottomRight = {
   347→          x: waistbandAnchors.bottomRight.x * img.width,
   348→          y: waistbandAnchors.bottomRight.y * img.height,
   349→        };
   350→
   351→        const srcX = Math.min(imgTopLeft.x, imgBottomLeft.x);
   352→        const srcY = Math.min(imgTopLeft.y, imgTopRight.y);
   353→        const srcWidth = Math.max(imgTopRight.x, imgBottomRight.x) - srcX;
   354→        const srcHeight = Math.max(imgBottomLeft.y, imgBottomRight.y) - srcY;
   355→
   356→        const bodyLeftHip = quad.topLeft;
   357→        const bodyRightHip = quad.topRight;
   358→        const bodyLeftAnkle = quad.bottomLeft;
   359→        const bodyRightAnkle = quad.bottomRight;
   360→
   361→        const bodyWidth = Math.hypot(
   362→          bodyRightHip.x - bodyLeftHip.x,
   363→          bodyRightHip.y - bodyLeftHip.y
   364→        );
   365→        const bodyHeight = Math.hypot(
   366→          bodyLeftAnkle.x - bodyLeftHip.x,
   367→          bodyLeftAnkle.y - bodyLeftHip.y
   368→        );
   369→
   370→        const scaleXVal = bodyWidth / srcWidth;
   371→        const scaleYVal = bodyHeight / srcHeight;
   372→        const scale = Math.min(scaleXVal, scaleYVal) * 1.1;
   373→
   374→        const renderWidth = srcWidth * scale;
   375→        const renderHeight = srcHeight * scale;
   376→
   377→        const bodyCenterX = (bodyLeftHip.x + bodyRightHip.x + bodyLeftAnkle.x + bodyRightAnkle.x) / 4;
   378→        const bodyCenterY = (bodyLeftHip.y + bodyRightHip.y + bodyLeftAnkle.y + bodyRightAnkle.y) / 4;
   379→
   380→        const rotation = Math.atan2(
   381→          bodyRightHip.y - bodyLeftHip.y,
   382→          bodyRightHip.x - bodyLeftHip.x
   383→        ) + Math.PI;
   384→
   385→        ctx.save();
   386→        ctx.translate(bodyCenterX, bodyCenterY);
   387→        ctx.rotate(rotation);
   388→        ctx.scale(-1, 1);
   389→        ctx.globalAlpha = opacity;
   390→
   391→        ctx.drawImage(
   392→          img,
   393→          srcX, srcY, srcWidth, srcHeight,
   394→          -renderWidth / 2, -renderHeight / 2, renderWidth, renderHeight
   395→        );
   396→
   397→        ctx.restore();
   398→      } else {
   399→        // Fallback: standard quad rendering without anchor points
   400→        const bounds = boundsRef.current.get(item.id) || {
   401→          x: 0,
   402→          y: 0,
   403→          width: img.width,
   404→          height: img.height,
   405→        };
   406→
   407→        const topWidth = Math.hypot(
   408→          quad.topRight.x - quad.topLeft.x,
   409→          quad.topRight.y - quad.topLeft.y
   410→        );
   411→        const bottomWidth = Math.hypot(
   412→          quad.bottomRight.x - quad.bottomLeft.x,
   413→          quad.bottomRight.y - quad.bottomLeft.y
   414→        );
   415→        const renderWidth = ((topWidth + bottomWidth) / 2) * 1.4;
   416→
   417→        const leftHeight = Math.hypot(
   418→          quad.bottomLeft.x - quad.topLeft.x,
   419→          quad.bottomLeft.y - quad.topLeft.y
   420→        );
   421→        const rightHeight = Math.hypot(
   422→          quad.bottomRight.x - quad.topRight.x,
   423→          quad.bottomRight.y - quad.topRight.y
   424→        );
   425→        const renderHeight = ((leftHeight + rightHeight) / 2) * 1.4;
   426→
   427→        const centerX = (quad.topLeft.x + quad.topRight.x + quad.bottomLeft.x + quad.bottomRight.x) / 4;
   428→        const centerY = (quad.topLeft.y + quad.topRight.y + quad.bottomLeft.y + quad.bottomRight.y) / 4;
   429→
   430→        const rotation = Math.atan2(
   431→          quad.topRight.y - quad.topLeft.y,
   432→          quad.topRight.x - quad.topLeft.x
   433→        ) + Math.PI;
   434→
   435→        ctx.save();
   436→        ctx.translate(centerX, centerY);
   437→        ctx.rotate(rotation);
   438→        ctx.globalAlpha = opacity;
   439→
   440→        ctx.drawImage(
   441→          img,
   442→          bounds.x, bounds.y, bounds.width, bounds.height,
   443→          -renderWidth / 2, -renderHeight / 2, renderWidth, renderHeight
   444→        );
   445→
   446→        // Subtle dashed border for fallback items
   447→        if (isFallback) {
   448→          ctx.strokeStyle = 'rgba(255, 200, 50, 0.3)';
   449→          ctx.lineWidth = 1.5;
   450→          ctx.setLineDash([6, 4]);
   451→          ctx.strokeRect(
   452→            -renderWidth / 2, -renderHeight / 2,
   453→            renderWidth, renderHeight
   454→          );
   455→          ctx.setLineDash([]);
   456→        }
   457→
   458→        ctx.restore();
   459→      }
   460→    }
   461→  }, [pose, items, width, height, loadedImages, opacity]);
