   252→  // ── Mira speech events (sentence-level streaming) ──
   253→  useEffect(() => {
   254→    // Regex for sentence boundaries: .!? followed by a space or end of string
   255→    const SENTENCE_BOUNDARY = /[.!?](?:\s|$)/;
   256→
   257→    /**
   258→     * Flush complete sentences from the buffer to TTS.
   259→     * Returns any remaining partial sentence left in the buffer.
   260→     */
   261→    function flushSentences(buffer: string, emotion: string): string {
   262→      let remaining = buffer;
   263→
   264→      while (true) {
   265→        const match = SENTENCE_BOUNDARY.exec(remaining);
   266→        if (!match) break;
   267→
   268→        // Split at the sentence boundary (include the punctuation)
   269→        const endIdx = match.index + match[0].length;
   270→        const sentence = remaining.slice(0, endIdx).trim();
   271→        remaining = remaining.slice(endIdx);
   272→
   273→        if (sentence) {
   274→          // Capture sentence in closure for the onStart callback
   275→          const displaySentence = sentence;
   276→          mira.speakQueued(
   277→            sentence,
   278→            emotion as MiraEmotion,
   279→            () => {
   280→              // Fires when TTS actually starts playing this sentence
   281→              setSpeechText(displaySentence);
   282→              setSpeechVisible(true);
   283→              if (speechFadeTimerRef.current) {
   284→                clearTimeout(speechFadeTimerRef.current);
   285→              }
   286→            },
   287→          );
   288→        }
   289→      }
   290→
   291→      return remaining;
   292→    }
   293→
   294→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   295→      // Ignore stale chunks from the pre-interrupt response
   296→      if (interruptedRef.current) {
   297→        if (data.is_chunk === false) {
   298→          interruptedRef.current = false; // Old response ended
   299→        }
   300→        return;
   301→      }
   302→
   303→      // Fallback session detection
   304→      if (!sessionActive && !isStarting) {
   305→        setKioskState("session");
   306→        setSessionActive(true);
   307→        setIsStarting(false);
   308→        mira.startSession();
   309→        stt.startListening();
   310→      }
   311→
   312→      if (data.is_chunk !== false) {
   313→        // ── Streaming chunk ──
   314→        if (!data.text) return;
   315→
   316→        sentenceBufferRef.current += data.text;
   317→
   318→        // Detect emotion from keywords in accumulated text
   319→        if (!emotionDetectedRef.current) {
   320→          const detected = detectEmotionFromText(sentenceBufferRef.current);
   321→          if (detected !== "idle") {
   322→            currentEmotionRef.current = detected;
   323→            emotionDetectedRef.current = true;
   324→          }
   325→        }
   326→
   327→        // Flush any complete sentences to TTS immediately
   328→        sentenceBufferRef.current = flushSentences(
   329→          sentenceBufferRef.current,
   330→          currentEmotionRef.current,
   331→        );
   332→      } else {
   333→        // ── End of message ──
   334→        if (data.text) {
   335→          sentenceBufferRef.current += data.text;
   336→        }
   337→
   338→        // Detect emotion if we haven't yet (short responses)
   339→        if (!emotionDetectedRef.current) {
   340→          currentEmotionRef.current = detectEmotionFromText(sentenceBufferRef.current);
   341→        }
   342→
   343→        // Flush any remaining text as the final sentence
   344→        const remainder = sentenceBufferRef.current.trim();
   345→        if (remainder) {
   346→          const displayRemainder = remainder;
   347→          mira.speakQueued(
   348→            remainder,
   349→            currentEmotionRef.current as MiraEmotion,
   350→            () => {
   351→              // Fires when TTS actually starts playing this sentence
   352→              setSpeechText(displayRemainder);
   353→              setSpeechVisible(true);
   354→              if (speechFadeTimerRef.current) {
   355→                clearTimeout(speechFadeTimerRef.current);
   356→              }
   357→            },
   358→          );
   359→        }
   360→
   361→        // Signal end of queue — drain callback will reset avatar state
   362→        mira.flushQueue();
   363→
   364→        // Reset for next response
   365→        sentenceBufferRef.current = "";
   366→        currentEmotionRef.current = "idle";
   367→        emotionDetectedRef.current = false;
   368→      }
   369→    };
   370→
   371→    socket.on("mira_speech", handleSpeech);
   372→    return () => {
   373→      socket.off("mira_speech", handleSpeech);
   374→    };
   375→    // eslint-disable-next-line react-hooks/exhaustive-deps
   376→  }, [sessionActive, isStarting]);
