   561→        gestureKeyRef.current += 1;
   562→        setGestureKey(gestureKeyRef.current);
   563→
   564→        if (canvasOutfits.length > 1) {
   565→          if (gesture.type === "swipe_left") {
   566→            setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   567→          } else if (gesture.type === "swipe_right") {
   568→            setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   569→          }
   570→        }
