   580→        });
   581→        return;
   582→      }
   583→
   584→      // Thumbs → hold-to-confirm (update last-seen time each frame)
   585→      const now = Date.now();
   586→      holdLastSeenRef.current = now;
   587→
   588→      // If gesture type changed, reset and start a fresh hold
   589→      if (holdGestureRef.current !== gesture.type) {
   590→        holdGestureRef.current = gesture.type;
   591→        holdStartRef.current = now;
   592→        setPendingGestureType(gesture.type);
