   602→  // staleness cancellation and dispatching at completion.
   603→  useEffect(() => {
   604→    const tick = () => {
   605→      holdRafRef.current = requestAnimationFrame(tick);
   606→
   607→      if (!holdGestureRef.current || !holdStartRef.current) return;
   608→
   609→      const now = Date.now();
   610→
   611→      // If gesture hasn't been seen in 300ms, cancel the hold
