   613→        holdGestureRef.current = null;
   614→        holdStartRef.current = null;
   615→        setPendingGestureType(null);
   616→        return;
   617→      }
   618→
   619→      // Hold completed → dispatch the gesture event
   620→      const elapsed = now - holdStartRef.current;
   621→      if (elapsed >= HOLD_DURATION_MS) {
   622→        const gestureType = holdGestureRef.current;
   623→
   624→        setLastGesture(gestureType);
   625→        gestureKeyRef.current += 1;
   626→        setGestureKey(gestureKeyRef.current);
