   632→            gesture: gestureType,
   633→            confidence: 1,
   634→            timestamp: Date.now(),
   635→          },
   636→        });
   637→
   638→        // Reset hold state
   639→        holdGestureRef.current = null;
   640→        holdStartRef.current = null;
   641→        setPendingGestureType(null);
   642→      }
   643→    };
   644→
   645→    holdRafRef.current = requestAnimationFrame(tick);
   646→    return () => cancelAnimationFrame(holdRafRef.current);
