  1013→/* ---------- Waiting Countdown ---------- */
  1014→
  1015→function WaitingCountdown() {
  1016→  const [remaining, setRemaining] = useState(120);
  1017→
  1018→  useEffect(() => {
  1019→    const timer = setInterval(() => {
  1020→      setRemaining((s) => {
  1021→        if (s <= 0) return 0;
  1022→        return s - 1;
  1023→      });
  1024→    }, 1000);
  1025→    return () => clearInterval(timer);
  1026→  }, []);
  1027→
  1028→  const minutes = Math.floor(remaining / 60);
  1029→  const seconds = remaining % 60;
  1030→
  1031→  return (
  1032→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
  1033→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
  1034→    </p>
  1035→  );
  1036→}
