            } else {
              fitStatusRef.current.set(item.id, 'fallback');
            }
          } catch (err) {
            console.warn("[MirrorV2:Canvas] Anchor detection failed, using fallback:", err);
            fitStatusRef.current.set(item.id, 'fallback');
